Please think it step-by-step to solve the above problem.

```cpp
#include "souvenirs.h"
#include <bits/stdc++.h>
using namespace std;

typedef long long ll;

struct Equation {
    ll V; // sum of prices for indices in S
    vector<int> S;
    Equation(ll V, const vector<int>& S) : V(V), S(S) {}
};

vector<Equation> eqs;
vector<ll> known;        // -1 if unknown
vector<int> cnt;         // number of souvenirs bought so far
vector<int> remain;      // remain[i] = i - cnt[i] (only for i>=1)
int N;
ll P0;

void resolve();

ll compute_safe_M() {
    ll best = LLONG_MAX;

    // from equations: floor( (V - sum_known) / #unknown_in_eq )
    for (const auto& e : eqs) {
        ll sum_known = 0;
        int unk = 0;
        for (int i : e.S) {
            if (known[i] != -1) sum_known += known[i];
            else                unk++;
        }
        if (unk == 0) continue;
        ll V_unk = e.V - sum_known;
        best = min(best, V_unk / unk);
    }

    // from neighbour upper bounds: if price of i-1 is known, then P[i] <= known[i-1] - 1
    for (int i = 1; i < N; ++i) {
        if (known[i] == -1 && i-1 >= 0 && known[i-1] != -1) {
            best = min(best, known[i-1] - 1);
        }
    }

    // avoid buying type 1 if its remaining is already 0
    if (known[1] != -1 && remain[1] == 0) {
        best = min(best, known[1] - 1);
    }

    // ensure M is at least 1 and less than P0
    best = max(best, 1LL);
    best = min(best, P0 - 1);
    return best;
}

void resolve() {
    bool changed;
    do {
        changed = false;
        for (const auto& e : eqs) {
            ll sum_known = 0;
            int unk_idx = -1;
            int unk_cnt = 0;
            for (int i : e.S) {
                if (known[i] == -1) {
                    unk_cnt++;
                    unk_idx = i;
                } else {
                    sum_known += known[i];
                }
            }
            if (unk_cnt == 1) {
                ll val = e.V - sum_known;
                if (known[unk_idx] == -1) {
                    known[unk_idx] = val;
                    changed = true;
                } else if (known[unk_idx] != val) {
                    // should not happen with consistent data
                }
            }
        }
    } while (changed);
}

void buy_souvenirs(int _N, ll _P0) {
    N = _N;
    P0 = _P0;
    known.assign(N, -1);
    known[0] = P0;
    cnt.assign(N, 0);
    remain.resize(N);
    for (int i = 1; i < N; ++i) remain[i] = i;

    // Initial transaction with M = P0-1 (always safe)
    auto res = transaction(P0 - 1);
    vector<int>& S0 = res.first;
    ll R0 = res.second;
    ll V0 = (P0 - 1) - R0;
    eqs.emplace_back(V0, S0);
    for (int i : S0) {
        cnt[i]++;
        remain[i] = i - cnt[i];
    }
    // Immediately resolve to possibly get some known prices (e.g., if S0 was a singleton)
    resolve();

    // Main loop: determine all unknown prices while respecting remaining budgets
    while (true) {
        bool all_known = true;
        for (int i = 1; i < N; ++i)
            if (known[i] == -1) { all_known = false; break; }
        if (all_known) break;

        ll M = compute_safe_M();
        res = transaction(M);
        vector<int>& S = res.first;
        ll R = res.second;
        ll V = M - R;
        eqs.emplace_back(V, S);
        for (int i : S) {
            cnt[i]++;
            remain[i] = i - cnt[i];
        }
        resolve();
    }

    // Now all prices are known. Buy the remaining required copies.
    for (int i = 1; i < N; ++i) {
        while (remain[i] > 0) {
            transaction(known[i]);   // this buys exactly one souvenir of type i
            cnt[i]++;
            remain[i]--;
        }
    }
}
```

