#include "triples.h"
#include <vector>
#include <unordered_map>
#include <cmath>

using namespace std;

long long count_triples(vector<int> H) {
    int N = H.size();
    long long ans = 0;

    // ------------- Pattern A (case 1) ---------------
    for (int i = 0; i < N; ++i) {
        int j = i + H[i];
        if (j < N) {
            int k = j + H[j];
            if (k < N && H[k] == H[i] + H[j]) {
                ans++;
            }
        }
    }

    // ------------- Pattern B (case 2) ---------------
    for (int i = 0; i < N; ++i) {
        int j = i + H[i];
        if (j < N && H[j] > H[i]) {
            int k = i + H[j];
            if (k < N && H[j] == H[i] + H[k]) {
                ans++;
            }
        }
    }

    // ------------- Pattern C (case 3) ---------------
    for (int j = 0; j < N; ++j) {
        int i = j - H[j];
        if (i >= 0) {
            int k = j + H[i];
            if (k < N && H[k] == H[i] + H[j]) {
                ans++;
            }
        }
    }

    // ------------- Pattern D (case 5) ---------------
    for (int j = 0; j < N; ++j) {
        int i = j - H[j];
        if (i >= 0 && H[i] > H[j]) {
            int k = i + H[i];
            if (k < N && H[i] == H[j] + H[k]) {
                ans++;
            }
        }
    }

    // ------------- Pattern E (case 6) ---------------
    {
        vector<vector<int>> forward(N);
        for (int i = 0; i < N; ++i) {
            int k = i + H[i];
            if (k < N) {
                forward[k].push_back(i);
            }
        }
        for (int k = 0; k < N; ++k) {
            const auto& vec = forward[k];
            unordered_map<int, int> freq;
            for (int idx : vec) {
                int need = H[idx] + H[k];
                auto it = freq.find(need);
                if (it != freq.end()) ans += it->second;
                freq[H[idx]]++;
            }
        }
    }

    // ------------- Pattern F (case 4) with heavy-light ---------------
    long long F = 0;
    {
        // Compute A[i] = i - H[i], B[i] = i + H[i]
        vector<int> A(N), B(N);
        for (int i = 0; i < N; ++i) {
            A[i] = i - H[i];
            B[i] = i + H[i];
        }

        // Count occurrences of each A and each B
        unordered_map<int, int> cntA, cntB;
        for (int i = 0; i < N; ++i) {
            cntA[A[i]]++;
            cntB[B[i]]++;
        }

        // Threshold for heavy
        int T = (int)sqrt(N) + 1;

        // Determine heavy values for A and B
        vector<int> heavyA, heavyB;
        unordered_map<int, int> idA, idB;
        unordered_map<int, bool> isHeavyA, isHeavyB;

        for (auto& p : cntA) {
            if (p.second > T) {
                idA[p.first] = heavyA.size();
                heavyA.push_back(p.first);
                isHeavyA[p.first] = true;
            }
        }
        for (auto& p : cntB) {
            if (p.second > T) {
                idB[p.first] = heavyB.size();
                heavyB.push_back(p.first);
                isHeavyB[p.first] = true;
            }
        }

        // Data structures
        unordered_map<int, unordered_map<int, int>> left_by_a;   // left_by_a[a][c] = count
        unordered_map<int, unordered_map<int, int>> right_by_b; // right_by_b[b][c] = count

        // Initially all indices in right
        for (int i = 0; i < N; ++i) {
            right_by_b[B[i]][A[i]]++;
        }

        // heavy_dot matrix for heavy (a,b)
        vector<vector<long long>> heavy_dot(heavyA.size(), vector<long long>(heavyB.size(), 0));

        // Sweep j from 0 to N-1
        for (int j = 0; j < N; ++j) {
            int a_j = A[j], b_j = B[j];

            // ---- Remove j from right ----
            // If b_j heavy, update heavy_dot for all heavy a
            if (isHeavyB[b_j]) {
                int idb = idB[b_j];
                for (size_t idx = 0; idx < heavyA.size(); ++idx) {
                    int a_val = heavyA[idx];
                    auto it_left = left_by_a.find(a_val);
                    if (it_left != left_by_a.end()) {
                        auto itc = it_left->second.find(a_j);
                        if (itc != it_left->second.end()) {
                            heavy_dot[idx][idb] -= itc->second;
                        }
                    }
                }
            }
            // Decrement right count
            auto& rmap = right_by_b[b_j];
            rmap[a_j]--;
            if (rmap[a_j] == 0) {
                rmap.erase(a_j);
                if (rmap.empty()) right_by_b.erase(b_j);
            }

            // ---- Contribution of this j ----
            long long contrib = 0;
            if (isHeavyA[a_j] && isHeavyB[b_j]) {
                int ida = idA[a_j];
                int idb = idB[b_j];
                contrib = heavy_dot[ida][idb];
            } else {
                // at least one side non-heavy
                auto& left_map = left_by_a[a_j];
                auto& right_map = right_by_b[b_j];
                if (!left_map.empty() && !right_map.empty()) {
                    if (left_map.size() <= right_map.size()) {
                        for (auto& p : left_map) {
                            int c = p.first;
                            int cntL = p.second;
                            auto it = right_map.find(c);
                            if (it != right_map.end()) {
                                contrib += (long long)cntL * it->second;
                            }
                        }
                    } else {
                        for (auto& p : right_map) {
                            int c = p.first;
                            int cntR = p.second;
                            auto it = left_map.find(c);
                            if (it != left_map.end()) {
                                contrib += (long long)it->second * cntR;
                            }
                        }
                    }
                }
            }
            F += contrib;

            // ---- Add j to left ----
            if (isHeavyA[a_j]) {
                int ida = idA[a_j];
                // For each heavy b, add right_by_b[b][b_j] to heavy_dot
                for (size_t idx = 0; idx < heavyB.size(); ++idx) {
                    int b_val = heavyB[idx];
                    int idb = idx;
                    auto it_right = right_by_b.find(b_val);
                    if (it_right != right_by_b.end()) {
                        auto itc = it_right->second.find(b_j);
                        if (itc != it_right->second.end()) {
                            heavy_dot[ida][idb] += itc->second;
                        }
                    }
                }
            }
            // Increment left count
            left_by_a[a_j][b_j]++;
        }
    }
    ans += F;

    // ------------ Overlaps: subtract double counted symmetric triples ------------
    long long overlap_i = 0, overlap_k = 0, overlap_j = 0;

    // overlaps for outer=i (case5 & case6)
    for (int j = 0; j < N; ++j) {
        int i = j - H[j];
        if (i < 0) continue;
        int k = j + H[j];
        if (k >= N) continue;
        if (H[i] == 2 * H[j] && H[k] == H[j]) overlap_i++;
    }

    // overlaps for outer=k (case1 & case3)
    for (int j = 0; j < N; ++j) {
        int i = j - H[j];
        if (i < 0) continue;
        int k = j + H[j];
        if (k >= N) continue;
        if (H[i] == H[j] && H[k] == 2 * H[j]) overlap_k++;
    }

    // overlaps for outer=j (case2 & case4)
    for (int j = 0; j < N; ++j) {
        if (H[j] % 2 == 0) {
            int d = H[j] / 2;
            int i = j - d;
            int k = j + d;
            if (i >= 0 && k < N && H[i] == d && H[k] == d) overlap_j++;
        }
    }

    ans = ans - overlap_i - overlap_j - overlap_k;

    return ans;
}

// Part II stub
vector<int> construct_range(int M, int K) {
    // Dummy implementation, not needed for Part I
    return {1, 1, 1};
}
