vector<int> max_coupons(int A, vector<int> P, vector<int> T) {
    int N = P.size();

    // ----- T=1 coupons -----
    vector<int> t1_idx;
    vector<long long> t1_price;
    long long total_T1 = 0;
    for (int i = 0; i < N; ++i) {
        if (T[i] == 1) {
            t1_idx.push_back(i);
            t1_price.push_back(P[i]);
            total_T1 += P[i];
        }
    }
    // sort T=1 by price
    int M1 = t1_idx.size();
    if (M1 > 0) {
        vector<pair<long long, int>> tmp;
        for (int i = 0; i < M1; ++i)
            tmp.emplace_back(t1_price[i], t1_idx[i]);
        sort(tmp.begin(), tmp.end());
        t1_idx.clear(); t1_price.clear();
        for (auto &p : tmp) {
            t1_price.push_back(p.first);
            t1_idx.push_back(p.second);
        }
    }
    vector<long long> pref(M1 + 1, 0);
    for (int i = 0; i < M1; ++i)
        pref[i + 1] = pref[i] + t1_price[i];

    // ----- T>1 coupons -----
    vector<Item> tgt;
    long long maxP = 0;
    for (int i = 0; i < N; ++i) {
        if (T[i] > 1) {
            tgt.push_back({i, (long long)P[i], T[i]});
            if (P[i] > maxP) maxP = P[i];
        }
    }
    int M = tgt.size();

    // if no T>1, answer comes only from T=1
    if (M == 0) {
        int k = upper_bound(pref.begin(), pref.end(), A) - pref.begin() - 1;
        vector<int> res;
        for (int i = 0; i < k; ++i)
            res.push_back(t1_idx[i]);
        return res;
    }

    // ----- sort T>1 by optimal order -----
    sort(tgt.begin(), tgt.end(), [](const Item &a, const Item &b) {
        // a before b iff a.P * a.T / (a.T-1) < b.P * b.T / (b.T-1)
        return (long long)a.P * a.T * (b.T - 1) <
               (long long)b.P * b.T * (a.T - 1);
    });

    // ----- cap for X -----
    long long BIG = max(2 * maxP, total_T1 + 1);

    // ----- DP over T>1 items -----
    // states[i] = frontier after processing first i items
    vector<vector<State>> states(M + 1);
    long long startX = (A > BIG) ? BIG : (long long)A;
    states[0].push_back({0, startX, -1, -1});

    for (int i = 0; i < M; ++i) {
        const Item &it = tgt[i];
        vector<State> candidates;

        // generate candidates from current frontier
        for (int sid = 0; sid < (int)states[i].size(); ++sid) {
            const State &s = states[i][sid];
            // option: do not take it
            candidates.push_back({s.cnt, s.X, sid, -1});
            // option: take it if affordable
            if (s.X >= it.P) {
                long long newX = (s.X - it.P) * it.T;
                if (newX > BIG) newX = BIG;
                candidates.push_back({s.cnt + 1, newX, sid, it.idx});
            }
        }

        // --- prune candidates to keep only non‑dominated states ---
        // 1) keep only one state per (cnt, X)
        map<pair<int, long long>, State> uniq;
        for (const State &st : candidates) {
            auto key = make_pair(st.cnt, st.X);
            if (uniq.find(key) == uniq.end())
                uniq[key] = st;
        }

        // 2) remove dominated states: a state (c,x) is dominated if there
        //    exists (c',x') with c' >= c and x' >= x.
        vector<State> filtered;
        for (auto &p : uniq)
            filtered.push_back(p.second);
        sort(filtered.begin(), filtered.end(), [](const State &a, const State &b) {
            if (a.cnt != b.cnt) return a.cnt > b.cnt;  // decreasing cnt
            return a.X > b.X;                           // tie by decreasing X
        });

        vector<State> next_states;
        long long maxX = -1;
        for (const State &st : filtered) {
            if (st.X > maxX) {
                next_states.push_back(st);
                maxX = st.X;
            }
        }

        states[i + 1] = next_states;
    }

    // ----- find the best final state -----
    int best_total = -1;
    int best_state_idx = -1;
    long long best_X = 0;
    for (int sid = 0; sid < (int)states[M].size(); ++sid) {
        const State &s = states[M][sid];
        int t1_cnt = upper_bound(pref.begin(), pref.end(), s.X) - pref.begin() - 1;
        int total = s.cnt + t1_cnt;
        if (total > best_total) {
            best_total = total;
            best_state_idx = sid;
            best_X = s.X;
        }
    }

    // ----- reconstruct the sequence of T>1 coupons -----
    vector<int> res;
    int cur_stage = M;
    int cur_idx = best_state_idx;
    while (cur_stage > 0) {
        const State &st = states[cur_stage][cur_idx];
        if (st.decision != -1)   // coupon was taken at this step
            res.push_back(st.decision);
        cur_idx = st.prev_id;
        --cur_stage;
    }
    reverse(res.begin(), res.end());

    // ----- add T=1 coupons (take smallest first, total ≤ best_X) -----
    int t1_taken = upper_bound(pref.begin(), pref.end(), best_X) - pref.begin() - 1;
    for (int i = 0; i < t1_taken; ++i)
        res.push_back(t1_idx[i]);

    return res;
}
