#include "migrations.h"
#include <vector>
#include <algorithm>
using namespace std;

const int LOG = 14;               // 2^14 > 10000

// Data structure to maintain the tree and current diameter
struct Tree {
    int N;
    vector<int> depth;
    vector<int> parent;
    vector<vector<int>> up;      // binary lifting table
    int curU, curV;              // current diameter endpoints, curU < curV
    int threshold;               // first index where we start sending messages
    bool phase;                  // false before threshold, true after
    vector<int> state_digits;    // 14 base‑4 digits of the state before the block
    int state_pos;               // next digit to send

    void init(int n) {
        N = n;
        depth.resize(N);
        parent.resize(N, -1);
        up.resize(LOG, vector<int>(N));
        depth[0] = 0;
        parent[0] = 0;                 // root’s parent is itself for LCA convenience
        for (int k = 0; k < LOG; ++k) up[k][0] = 0;
        curU = curV = 0;
        threshold = N - 50;            // we will send messages on the last 50 nodes
        phase = false;
        state_digits.resize(14);
        state_pos = 0;
    }

    // LCA using binary lifting
    int lca(int u, int v) {
        if (depth[u] < depth[v]) swap(u, v);
        int diff = depth[u] - depth[v];
        for (int k = 0; k < LOG; ++k)
            if (diff >> k & 1) u = up[k][u];
        if (u == v) return u;
        for (int k = LOG - 1; k >= 0; --k)
            if (up[k][u] != up[k][v]) {
                u = up[k][u];
                v = up[k][v];
            }
        return up[0][u];
    }

    // Distance between two nodes
    int dist(int u, int v) {
        int w = lca(u, v);
        return depth[u] + depth[v] - 2 * depth[w];
    }

    // Insert node i with parent Pi
    void add_node(int i, int Pi) {
        parent[i] = Pi;
        depth[i] = depth[Pi] + 1;
        up[0][i] = Pi;
        for (int k = 1; k < LOG; ++k)
            up[k][i] = up[k - 1][up[k - 1][i]];
    }

    // Update current diameter after adding node i; t is the transition code
    void update_state(int i, int t) {
        if (t == 1) {               // replace the smaller endpoint (curU)
            int newU = curV;
            int newV = i;
            curU = newU;
            curV = newV;
        } else if (t == 2) {        // replace the larger endpoint (curV)
            curV = i;
        }
        // keep order curU < curV
        if (curU > curV) swap(curU, curV);
    }
};

static Tree tree;

// Research team’s procedure
int send_message(int N, int i, int Pi) {
    static bool initialized = false;
    if (!initialized) {
        tree.init(N);
        initialized = true;
    }

    // ----- compute transition code t before node i is added -----
    int du = tree.dist(Pi, tree.curU) + 1;
    int dv = tree.dist(Pi, tree.curV) + 1;
    int curDiam = tree.dist(tree.curU, tree.curV);
    int t = 0;
    if (max(du, dv) > curDiam) {
        if (du > dv) t = 2;          // replace larger endpoint
        else if (dv > du) t = 1;     // replace smaller endpoint
        else t = 2;                  // tie: replace larger
    }

    // ----- if we are at the beginning of the message block, store the state digits -----
    if (i == tree.threshold) {
        auto store_digits = [&](int x, int offset) {
            int digs[7];
            int tmp = x;
            for (int j = 6; j >= 0; --j) {
                digs[j] = tmp % 4;
                tmp /= 4;
            }
            for (int j = 0; j < 7; ++j)
                tree.state_digits[offset + j] = digs[j];
        };
        store_digits(tree.curU, 0);   // first 7 digits
        store_digits(tree.curV, 7);   // next 7 digits
        tree.phase = true;
    }

    // ----- determine the value to send -----
    int val = 0;
    if (tree.phase) {
        if (tree.state_pos < 14) {              // still sending state digits
            int d = tree.state_digits[tree.state_pos++];
            val = d * 3 + t + 1;                // combined digit and transition
        } else {
            val = t + 1;                        // only transition
        }
    }

    // ----- finally insert the node and update the internal state -----
    tree.add_node(i, Pi);
    tree.update_state(i, t);

    return val;
}

