pair<int, int> longest_path(vector<int> S) {
    int N = S.size();
    const int TH = N - 50;           // first of the last 50 indices

    vector<int> trans(50);           // transition codes
    vector<int> digits(14);          // base‑4 digits of the initial state

    for (int j = 0; j < 50; ++j) {
        int val = S[TH + j];
        if (j < 14) {
            int d = (val - 1) / 3;
            int t = (val - 1) % 3;
            digits[j] = d;
            trans[j] = t;
        } else {
            trans[j] = val - 1;      // no state digit, just transition
        }
    }

    // reconstruct a and b (the two endpoints before the block)
    int a = 0, b = 0;
    for (int j = 0; j < 7; ++j)  a = a * 4 + digits[j];
    for (int j = 7; j < 14; ++j) b = b * 4 + digits[j];
    int curU = a, curV = b;
    if (curU > curV) swap(curU, curV);

    // simulate the last 50 additions
    for (int j = 0; j < 50; ++j) {
        int i = TH + j;
        int t = trans[j];
        if (t == 1) {                 // replace smaller endpoint
            int newU = curV;
            int newV = i;
            curU = newU;
            curV = newV;
        } else if (t == 2) {          // replace larger endpoint
            curV = i;
        }
        if (curU > curV) swap(curU, curV);
    }

    return {curU, curV};
