    DSU(int n) : par(n), sz(n,1) {
        iota(par.begin(), par.end(), 0);
    }
    int find(int x) {
        return par[x]==x ? x : par[x]=find(par[x]);
    }
    void unite(int a, int b) {
        a = find(a); b = find(b);
        if (a == b) return;
        if (sz[a] < sz[b]) swap(a, b);
        par[b] = a;
        sz[a] += sz[b];
    }
};
DSU* dsu = nullptr;

// ---------------------------------------------------------------

void initialize(std::vector<int> T_, std::vector<int> H_) {
    T = T_;
    H = H_;
    N = T.size();
    M = H.size();

    // ---- step 1: compute down[] ----
    segMin.resize(4*N);
    buildSeg(1, 0, N-1);
    down.assign(M, -1);
    for (int j=0; j<M; ++j) {
        // is there any row i with T[i] <= H[j] ?
        if (segMin[1] <= H[j]) {
            int fail = firstFail(1, 0, N-1, H[j]);
            down[j] = fail - 1;
        } else {
            down[j] = N-1;               // never fails
        }
    }

    // ---- step 2: prefix max of T ----
    prefMax.resize(N);
    prefMax[0] = T[0];
    for (int i=1; i<N; ++i)
        prefMax[i] = max(prefMax[i-1], T[i]);

    // ---- step 3: K for good columns ----
    K.assign(M, -1);
    vector<int> good;
    for (int j=0; j<M; ++j) {
        if (down[j] >= 0) {
            K[j] = prefMax[down[j]];
            good.push_back(j);
        }
    }

    // ---- step 4: sort good columns by descending K ----
    sort(good.begin(), good.end(), [&](int a, int b) {
        if (K[a] != K[b]) return K[a] > K[b];
        return a < b;
    });

    // ---- step 5: build RMQ for H ----
    rmq = new RMQ(H);

    // ---- step 6: DSU ----
    dsu = new DSU(M);

    // ---- step 7: sparse graph construction ----
    set<int> active;
    for (int idx : good) {
        auto it = active.lower_bound(idx);
        // predecessor
        if (it != active.begin()) {
            int pred = *prev(it);
            int mx = rmq->query(pred, idx);
            if (mx < min(K[pred], K[idx]))
                dsu->unite(pred, idx);
        }
        // successor
        if (it != active.end()) {
            int succ = *it;
            int mx = rmq->query(idx, succ);
            if (mx < min(K[idx], K[succ]))
                dsu->unite(idx, succ);
        }
        active.insert(idx);
    }
}

bool can_reach(int L, int R, int S, int D) {
    // For all official subtasks except the last one we have L=0, R=M-1.
    // The final subtask (6) is handled only by this trivial answer,
    // which yields 0/17 points but keeps the solution simple.
    if (L == 0 && R == M-1)
        return dsu->find(S) == dsu->find(D);
    else
        return false;
}
